#!/usr/bin/env node
/**
 * Session 6: 100 MC-Fragen (Recht).
 */
import fs from 'node:fs/promises'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const OUT = path.join(__dirname, 'fragen-updates.jsonl')
const STATE = path.join(__dirname, 'state.json')

const updates = [
  { id: '9a76bf6b-c540-4d7d-9446-bc3375909035', fachbereich: 'Recht', musterlosung: 'Der Mietvertrag ist nach OR 11 formfrei — auch mündlich gültig. Das Problem liegt nicht in der Gültigkeit, sondern in der Beweisbarkeit: Ohne schriftlichen Vertrag kann keine Partei die vereinbarten Bedingungen eindeutig beweisen. Ein schriftlicher Vertrag ist daher nicht rechtlich erforderlich, aber praktisch sehr empfehlenswert.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Ein mündlicher Mietvertrag ist gültig — Formfreiheit nach OR 11.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Beweisproblem — ohne Schriftform kann keine Partei die Vereinbarung beweisen.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine Vermutung zugunsten des Vermieters — Beweislast folgt Art. 8 ZGB.' }, { feld: 'optionen', id: 'opt-3', text: 'Ein mündlicher Mietvertrag wird nicht automatisch ungültig — Formfreiheit bleibt.' } ] },
  { id: '9ad37399-a664-4e9f-9cbd-dc38fabf5f14', fachbereich: 'Recht', musterlosung: 'Primär verantwortlich für die Umsetzung der Menschenrechte sind die einzelnen Staaten. Das bringt ein grundlegendes Paradox mit sich: Gerade jene Staaten, die Menschenrechte verletzen, sollen diese gleichzeitig schützen. NGOs wie Amnesty International übernehmen deshalb eine wichtige Überwachungs- und Anprangerungsfunktion.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die UNO koordiniert, aber die Umsetzung liegt primär bei den Staaten.' }, { feld: 'optionen', id: 'opt-1', text: 'Der IGH klärt zwischenstaatliche Streitigkeiten — nicht die Umsetzung allgemein.' }, { feld: 'optionen', id: 'opt-2', text: 'NGOs überwachen, sind aber nicht primär verantwortlich für die Umsetzung.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Die einzelnen Staaten tragen die primäre Umsetzungsverantwortung.' } ] },
  { id: '9ad96998-2dfe-4974-bc5a-4f90a5b5d014', fachbereich: 'Recht', musterlosung: 'Der geringfügige Diebstahl unter Angehörigen ist ein Antragsdelikt. Nach Art. 30 StGB werden Antragsdelikte nur auf Antrag des Opfers verfolgt. Stellt die Mutter keinen Strafantrag, bleibt Hansli straffrei. Hintergrund: Bei leichteren Delikten im familiären Umfeld soll das Opfer selbst entscheiden, ob eine Strafverfolgung gewünscht ist.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Geringfügiger Diebstahl unter Angehörigen ist Antragsdelikt — nicht von Amtes wegen verfolgt.' }, { feld: 'optionen', id: 'opt-1', text: 'Die Polizei entscheidet nicht selbst — die Rechtsordnung bestimmt es.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine Bestrafung ohne Strafantrag — die Verfolgung setzt Antrag voraus.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Ohne Strafantrag keine Verfolgung — Hansli bleibt straffrei.' } ] },
  { id: '9b8b8944-56ad-47f5-9e0f-b0a4e1e82365', fachbereich: 'Recht', musterlosung: 'Forderung und Schuld sind zwei Seiten derselben Obligation: Die Forderung ist das einklagbare Recht des Gläubigers auf eine Leistung, die Schuld die Pflicht des Schuldners zur Erbringung dieser Leistung. Beide Begriffe beschreiben dieselbe Rechtsbeziehung aus unterschiedlicher Perspektive.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Verdreht — Forderung = Recht des Gläubigers, Schuld = Pflicht des Schuldners.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Forderung = Gläubigerrecht, Schuld = Schuldnerpflicht.' }, { feld: 'optionen', id: 'opt-2', text: 'Falsch — beide Begriffe gelten für alle Leistungsarten, nicht nur Geld oder Sachen.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine Synonyme — sie bezeichnen zwei Perspektiven derselben Obligation.' } ] },
  { id: '9bacedf4-9dac-4c74-8501-1a25bc054fc3', fachbereich: 'Recht', musterlosung: 'Der GAV ist für die gebundenen Parteien verbindlich. Eine vertragliche Vereinbarung, die den GAV-Mindestlohn unterschreitet, ist nichtig (OR 357). Der Arbeitnehmer kann die Lohndifferenz einklagen und erhält nachträglich den GAV-konformen Lohn — ggf. mit Verzugszins und Schadenersatz.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Formfreiheit hebt GAV-Mindestlöhne nicht auf — sie sind zwingend.' }, { feld: 'optionen', id: 'opt-1', text: 'Der GAV bleibt gültig — die vertragliche Unterschreitung ist nichtig.' }, { feld: 'optionen', id: 'opt-2', text: 'Der AN hat sehr wohl Anspruch — auf die GAV-konforme Lohnhöhe.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: AN kann die Lohndifferenz einklagen.' } ] },
  { id: '9bb63e7a-8d0a-45af-ad3a-20b176237f08', fachbereich: 'Recht', musterlosung: 'Das Jugendstrafgesetz (JStG) sieht vier Bestrafungsmöglichkeiten vor: Verweis (JStG 22) als förmliche Missbilligung, persönliche Leistung (JStG 23) als gemeinnützige Arbeit oder Kurs, Busse (JStG 24, bis CHF 2\'000) und Freiheitsentzug (JStG 25, ab 15 Jahren). Die Erwachsenen-Strafrahmen gelten nicht für Jugendliche.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Jugendliche haben eigene, mildere Sanktionen — nicht Erwachsenenstrafen.' }, { feld: 'optionen', id: 'opt-1', text: 'Unvollständig — Verweis und persönliche Leistung fehlen.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Verweis, persönliche Leistung, Busse, Freiheitsentzug (JStG 22–25).' }, { feld: 'optionen', id: 'opt-3', text: 'Unvollständig — persönliche Leistung und Freiheitsentzug fehlen.' } ] },
  { id: '9bed8b4a-0871-4501-b538-7fa6d099c20e', fachbereich: 'Recht', musterlosung: 'Die Übervorteilung ist in OR 21 geregelt: Wird ein Vertrag geschlossen, bei dem ein offenbares Missverhältnis zwischen Leistung und Gegenleistung besteht und die Notlage, Unerfahrenheit oder Leichtsinnigkeit einer Partei ausgenutzt wird, kann die Benachteiligte den Vertrag innert Jahresfrist anfechten.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'OR 24 regelt die Irrtümer (Erklärungs- und Grundlagenirrtum).' }, { feld: 'optionen', id: 'opt-1', text: 'OR 29 regelt die Furchterregung — andere Anfechtungsgrund.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: OR 21 regelt die Übervorteilung.' }, { feld: 'optionen', id: 'opt-3', text: 'OR 28 regelt die absichtliche Täuschung.' } ] },
  { id: '9d3982ef-55d6-4082-bbdd-5c1b9c5b1907', fachbereich: 'Recht', musterlosung: 'Die Rechtsfähigkeit (Rechtspersönlichkeit) einer juristischen Person beginnt mit dem Eintrag ins Handelsregister. Ab diesem Zeitpunkt kann sie Rechte und Pflichten haben — Verträge schliessen, Eigentum erwerben, klagen und verklagt werden. Die Rechtsfähigkeit endet mit der Löschung aus dem Handelsregister.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die VR-Wahl ist interne Organisation — nicht der Rechtsfähigkeitsbeginn.' }, { feld: 'optionen', id: 'opt-1', text: 'Die Geschäftstätigkeit setzt bereits Rechtsfähigkeit voraus.' }, { feld: 'optionen', id: 'opt-2', text: 'Die Gründungsversammlung beschliesst die Gründung — die Rechtspersönlichkeit entsteht erst mit HR-Eintrag.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Eintrag ins Handelsregister begründet die Rechtsfähigkeit.' } ] },
  { id: '9d69eaa7-1e24-46cd-96bd-eec52cc7d5d0', fachbereich: 'Recht', musterlosung: 'Art. 97 OR kehrt die Beweislast im Vertragsrecht um: Bei Nichterfüllung wird vermutet, dass der Schuldner schuldhaft gehandelt hat. Der Gläubiger muss das Verschulden nicht beweisen — umgekehrt muss der Schuldner beweisen, dass ihn kein Verschulden trifft. Dies ist eine gesetzliche Ausnahme zum Grundprinzip von Art. 8 ZGB.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Art. 97 OR hebt Art. 8 nicht auf — er ist nur eine Ausnahme in diesem Bereich.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Beweislastumkehr — Schuldner muss Entlastung beweisen.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine gleiche Regel — Beweislast umgekehrt zugunsten des Gläubigers.' }, { feld: 'optionen', id: 'opt-3', text: 'Art. 97 OR ist Zivilrecht — nicht Strafrecht.' } ] },
  { id: '9d80ebf5-6aa5-444e-8ce8-fe71fde26349', fachbereich: 'Recht', musterlosung: 'Wird die AG-Struktur rechtsmissbräuchlich eingesetzt (Art. 2 Abs. 2 ZGB), können die Gerichte den «Schleier der juristischen Person» durchdringen und direkt auf den Aktionär durchgreifen (Durchgriffshaftung / Piercing the corporate veil). Voraussetzung: Die AG war von Anfang an nicht lebensfähig oder wurde durch Vermögensentzug künstlich geschwächt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Verluste allein sind kein Grund für Durchgriff — normaler Unternehmenszweck.' }, { feld: 'optionen', id: 'opt-1', text: 'Die blosse Funktion als Geschäftsführer rechtfertigt keinen Durchgriff.' }, { feld: 'optionen', id: 'opt-2', text: 'Aktionärszahl ist kein Durchgriffskriterium — Rechtsmissbrauch zählt.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Rechtsmissbräuchliche Konstruktion begründet Durchgriffshaftung.' } ] },
  { id: '9da05b9c-5dcd-4443-bfe2-511cbc28b941', fachbereich: 'Recht', musterlosung: 'Art. 10 BV verbietet in der Schweiz die Todesstrafe sowie körperliche Strafen wie Folter und Prügelstrafe. Die Todesstrafe ist seit 1874 auf Bundesebene abgeschafft und seit 1992 auch für Kriegsverbrechen verboten. Sie ist Teil des unantastbaren Kerngehalts der persönlichen Freiheit.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die lebenslange Freiheitsstrafe ist zulässig — Art. 40 StGB.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Todesstrafe und Folter sind verboten (Art. 10 BV).' }, { feld: 'optionen', id: 'opt-2', text: 'Geldstrafe ist Standardsanktion (Art. 34 StGB) — nicht verboten.' }, { feld: 'optionen', id: 'opt-3', text: 'Busse ist die normale Übertretungsstrafe (Art. 106 StGB).' } ] },
  { id: '9f2c1b12-3ca7-46dc-9a64-b58caa52128d', fachbereich: 'Recht', musterlosung: 'Die Nutzniessung (Art. 745–775 ZGB) ist die einzige Dienstbarkeit, die an beweglichen Sachen, Rechten oder ganzen Vermögen bestehen kann. Der Nutzniesser hat Besitz, Gebrauch und Nutzung (Art. 755). Das Nutzniessungsvermögen muss im Bestand erhalten bleiben (Art. 764). Die Nutzniessung ist untrennbar mit der Person verbunden und nicht vererblich (Art. 748).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Nutzniessung gilt an Grundstücken, beweglichen Sachen, Rechten und Vermögen.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Besitz, Gebrauch und Nutzung gehören zu den Rechten des Nutzniessers.' }, { feld: 'optionen', id: 'opt-2', text: 'Falsch — das Vermögen muss im Bestand erhalten bleiben (Art. 764 Abs. 1 ZGB).' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Die Nutzniessung ist persönlich und nicht vererblich (Art. 748 ZGB).' } ] },
  { id: 'a08c338c-8cb8-43ff-aaae-1d229886f59c', fachbereich: 'Recht', musterlosung: 'Das Arbeitsgesetz (ArG) ist öffentliches Arbeitsrecht: relativ zwingend, mit Schutzvorschriften für Arbeitszeiten und besonders schützenswerte Gruppen (Schwangere, Stillende, Jugendliche). Leitende Angestellte sind nach Art. 3 lit. d ArG ausgenommen. Nachtarbeit ist nicht generell verboten — sie ist zulässig mit Bewilligung und Lohnzuschlag.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Höchstarbeitszeiten und Pausenregelungen sind Kerninhalt des ArG.' }, { feld: 'optionen', id: 'opt-1', text: 'Falsch — leitende Angestellte sind nach Art. 3 lit. d ArG ausgenommen.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Schutzbestimmungen für Schwangere und Stillende.' }, { feld: 'optionen', id: 'opt-3', text: 'Falsch — Nachtarbeit ist bewilligungs- und zuschlagspflichtig, nicht verboten.' } ] },
  { id: 'a09a7739-1949-4df3-ab50-b19cca4a4238', fachbereich: 'Recht', musterlosung: 'Nach Art. 3 Abs. 2 ZGB kann sich nicht auf den guten Glauben berufen, wer bei der gebotenen Aufmerksamkeit den Mangel hätte erkennen können. Ein verdächtig tiefer Preis (13\'000 statt 19\'250) hätte den Garagisten zur Prüfung des Eigentumsvorbehaltsregisters verpflichtet. Seine Unterlassung schliesst den Schutz aus.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Kein Gewohnheitsrecht — Art. 3 ZGB ist geschriebenes Recht.' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht beide gleichzeitig — Abs. 2 ist die relevante Schranke.' }, { feld: 'optionen', id: 'opt-2', text: 'Abs. 1 (Vermutung des guten Glaubens) wird durch Abs. 2 eingeschränkt.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Art. 3 Abs. 2 ZGB — fehlende Aufmerksamkeit schliesst guten Glauben aus.' } ] },
  { id: 'a0e31ded-7fe3-4b70-9d45-4d5004b1dba1', fachbereich: 'Recht', musterlosung: 'Ein Strafverfahren läuft in fünf Phasen ab: (1) Strafanzeige oder Strafantrag leitet das Verfahren ein, (2) Vorverfahren mit polizeilicher Ermittlung und staatsanwaltschaftlicher Untersuchung, (3) Anklageerhebung durch die Staatsanwaltschaft, (4) Hauptverhandlung vor Gericht, (5) Urteil. Rechtsmittel können anschliessend eingelegt werden.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Strafanzeige → Vorverfahren → Anklageerhebung → Hauptverhandlung → Urteil.' }, { feld: 'optionen', id: 'opt-1', text: 'Das ist der Zivilprozess — nicht das Strafverfahren.' }, { feld: 'optionen', id: 'opt-2', text: 'Urteil kommt am Ende — nicht direkt nach Anzeige.' }, { feld: 'optionen', id: 'opt-3', text: 'Reihenfolge durcheinander — Ermittlung kommt vor Anklageerhebung.' } ] },
  { id: 'a19b4bb6-9197-4468-a0b5-306b5e3faf1a', fachbereich: 'Recht', musterlosung: 'Nach Art. 272b Abs. 1 OR kann eine Wohnungsmiete maximal vier Jahre erstreckt werden, eine Geschäftsmiete maximal sechs Jahre. Voraussetzung ist ein Härtefall (Art. 272 OR) — die Kündigung hätte für den Mieter oder seine Familie unzumutbare Folgen. Das Begehren muss bei der Schlichtungsbehörde gestellt werden.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Unbeschränkt wäre zu weit — die Erstreckung ist gesetzlich begrenzt.' }, { feld: 'optionen', id: 'opt-1', text: '1 Jahr ist zu kurz — 4 Jahre sind das Maximum bei Wohnungen.' }, { feld: 'optionen', id: 'opt-2', text: '2 Jahre ist zu kurz — 4 Jahre sind das Maximum.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Maximal 4 Jahre bei Wohnungen (Art. 272b Abs. 1 OR).' } ] },
  { id: 'a2b02434-c6d5-4a2c-ad00-8f1c79ea5b61', fachbereich: 'Recht', musterlosung: 'Bei einem Sachmangel hat der Käufer nach OR 205/206 drei Wahlrechte: Wandelung (Rückgängigmachung des Vertrags, OR 205), Minderung (Preisreduktion, OR 205) oder Ersatzlieferung einer mangelfreien Sache (OR 206 Abs. 1). Voraussetzung ist die rechtzeitige Mängelrüge (OR 201). Der Käufer wählt unter den drei Optionen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Drei Wahlrechte — Wandelung, Minderung, Ersatzlieferung (OR 205/206).' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht nur Rücktritt — auch Minderung und Ersatzlieferung stehen zur Verfügung.' }, { feld: 'optionen', id: 'opt-2', text: 'Reparatur ist keine gesetzliche Option — nur die drei Wahlrechte.' }, { feld: 'optionen', id: 'opt-3', text: 'Annahme schliesst Mängelrechte nicht aus — bei rechtzeitiger Rüge bleiben sie erhalten.' } ] },
  { id: 'a36a6ca0-c101-4754-9b03-b391ab2579b3', fachbereich: 'Recht', musterlosung: 'Nach Art. 714 ZGB bedarf es zur Übertragung des Fahrniseigentums des Übergangs des Besitzes. K. Etter hat zwar den Kaufpreis bezahlt, aber die Weine wurden ihm nie geliefert — der Besitz ging nie auf ihn über. Ohne Besitzübergang kein Eigentumsübergang. Er kann keine Aussonderung verlangen, sondern nur eine Forderung im Konkurs anmelden.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Zahlung allein begründet kein Eigentum — Besitzübergang ist erforderlich.' }, { feld: 'optionen', id: 'opt-1', text: 'Die blosse Bereitstellung in Kisten überträgt noch keinen Besitz auf K.' }, { feld: 'optionen', id: 'opt-2', text: 'Barkauf macht keinen Unterschied — der Besitzübergang ist das entscheidende Kriterium.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Ohne Besitzübergang kein Eigentum — nur Konkursforderung möglich.' } ] },
  { id: 'a38f120a-7328-41dd-8dac-4c4258f0e630', fachbereich: 'Recht', musterlosung: 'Recht regelt das äussere Verhalten und ist staatlich erzwingbar. Die innere Einstellung ist rechtlich irrelevant: Ob jemand nicht stiehlt, weil er es für falsch hält oder weil er Angst vor Strafe hat, ist gleichgültig — entscheidend ist die Normkonformität des Verhaltens. Dies unterscheidet Recht von Moral, die auf innere Überzeugung abstellt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Recht betrifft äusseres Verhalten — nicht Gesinnung.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Staatliche Erzwingbarkeit unterscheidet Recht von Moral/Sitte.' }, { feld: 'optionen', id: 'opt-2', text: 'Falsch — Recht verlangt gerade keine innere Überzeugung.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Nur Normkonformität zählt, nicht die innere Haltung.' } ] },
  { id: 'a3dc780b-7cb7-4746-b62f-159622ede66f', fachbereich: 'Recht', musterlosung: 'Beim Erwerb vom Nichteigentümer sind zwei Voraussetzungen entscheidend: (1) War die Sache dem Eigentümer anvertraut (freiwillig aus der Hand gegeben, z.B. geliehen/vermietet) oder abhandengekommen (gestohlen/verloren)? (2) War der Erwerber gutgläubig? Diese Unterscheidung führt zu verschiedenen Rechtsfolgen nach Art. 933 und 934 ZGB.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Anvertraut vs. abhandengekommen + Gutgläubigkeit des Erwerbers.' }, { feld: 'optionen', id: 'opt-1', text: 'Vorstrafen des Veräusserers sind kein Kriterium.' }, { feld: 'optionen', id: 'opt-2', text: 'Öffentlichkeit des Verkaufs allein reicht nicht — Anvertrauung und Gutgläubigkeit entscheiden.' }, { feld: 'optionen', id: 'opt-3', text: 'Der Kaufpreis ist nicht das primäre Kriterium (kann aber auf Gutgläubigkeit hindeuten).' } ] },
  { id: 'a3dfd58f-6b5c-46a2-bf51-3aa8a1ccc411', fachbereich: 'Recht', musterlosung: 'Eine Kündigung wegen Gewerkschaftsmitgliedschaft oder Streikbeteiligung ist nach Art. 336 Abs. 1 lit. a OR missbräuchlich. Die Regel schützt die Koalitionsfreiheit (Art. 28 BV). Der Arbeitnehmer kann die Kündigung anfechten und Entschädigung bis zu 6 Monatslöhnen verlangen (Art. 336a OR). Leistungsmängel oder Probezeit sind dagegen keine missbräuchlichen Gründe.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Personalmangel ist ein sachlicher Grund — nicht missbräuchlich.' }, { feld: 'optionen', id: 'opt-1', text: 'Leistungsmängel sind zulässiger Kündigungsgrund — nicht missbräuchlich.' }, { feld: 'optionen', id: 'opt-2', text: 'Probezeitkündigung ist zulässig und nicht missbräuchlich.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Gewerkschaftsmitgliedschaft schützt Art. 336 Abs. 1 lit. a OR.' } ] },
  { id: 'a568db15-62de-48e7-84f4-3d98f36ab398', fachbereich: 'Recht', musterlosung: 'Beim Sale-and-Lease-back kauft der Vater die Maschine und stellt sie Peter via Leasingvertrag wieder zur Verfügung (Besitzkonstitut nach Art. 717 ZGB). Der Vater erwirbt Eigentum, Peter wird unselbständiger Besitzer. Das Geschäft ist grundsätzlich gültig — der Vater kann die Maschine im Konkurs als sein Eigentum aussondern lassen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Verwandte können rechtsgültige Geschäfte abschliessen — keine automatische Nichtigkeit.' }, { feld: 'optionen', id: 'opt-1', text: 'Besitzkonstitut ersetzt die physische Übergabe — rechtsgültig nach Art. 717 ZGB.' }, { feld: 'optionen', id: 'opt-2', text: 'Barzahlung ist kein Gültigkeitserfordernis beim Sale-and-Lease-back.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Eigentum durch Besitzkonstitut — Aussonderung zulässig.' } ] },
  { id: 'a5998c2f-ac43-4788-88d9-72f2e1558d8d', fachbereich: 'Recht', musterlosung: 'Nach OR 74 Abs. 2 Ziff. 3 ist der Erfüllungsort bei Gattungsschulden (nur der Art nach bestimmte Leistungen) am Wohnsitz des Schuldners bei Entstehung der Obligation. Der Gläubiger muss die Ware dort abholen — typische Holschuld. Anders als bei Geldschulden (Bringschuld zum Gläubiger) oder Speziesschulden (Standort der Sache).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Der Produktionsort ist rechtlich irrelevant — der Schuldnerwohnsitz zählt.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Schuldnerwohnsitz bei Schuldentstehung (OR 74 Abs. 2 Ziff. 3).' }, { feld: 'optionen', id: 'opt-2', text: 'Gläubigerwohnsitz gilt bei Geldschulden — nicht bei Gattungsschulden.' }, { feld: 'optionen', id: 'opt-3', text: 'Marktplatz ist kein gesetzlicher Erfüllungsort.' } ] },
  { id: 'a637b66c-5683-478a-af6f-cfa74f87bd17', fachbereich: 'Recht', musterlosung: 'Der Grundsatz «Lex posterior derogat legi priori» bedeutet: Das jüngere (neuere) Recht geht dem älteren Recht vor. Beim Erlass eines neuen Gesetzes bemüht sich der Gesetzgeber, widersprechende ältere Erlasse formell aufzuheben. Bei Widersprüchen gilt die spätere Norm.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Hierarchie (übergeordnet vor untergeordnet) ist ein anderer Grundsatz («Lex superior»).' }, { feld: 'optionen', id: 'opt-1', text: 'Das ist Art. 49 BV (Bundesrecht bricht kantonales) — nicht «lex posterior».' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Jüngeres Recht geht älterem vor.' }, { feld: 'optionen', id: 'opt-3', text: 'Das ist «lex specialis» — spezielles vor allgemeinem Recht.' } ] },
  { id: 'a7171aa4-8c58-4f2a-80f3-a333bce06de4', fachbereich: 'Recht', musterlosung: 'Die AEMR ist umstritten wegen: (1) Universalismus vs. Kulturrelativismus — manche Staaten argumentieren, die Menschenrechte seien westlich geprägt; (2) Gewichtung der Dimensionen — westliche Staaten betonen bürgerlich-politische Rechte, andere wirtschaftlich-soziale; (3) Spannungsfeld zwischen staatlicher Souveränität und internationaler Durchsetzung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Universalismus vs. Kulturrelativismus — zentraler Streitpunkt.' }, { feld: 'optionen', id: 'opt-1', text: 'Die Anzahl der Artikel ist nicht das eigentliche Streitthema.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Gewichtung bürgerlich-politisch vs. wirtschaftlich-sozial.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Souveränität vs. internationale Durchsetzung.' } ] },
  { id: 'a73cd3c9-944a-481d-a0f5-1b9740d1d6ca', fachbereich: 'Recht', musterlosung: 'Auch autoritäre Staaten haben formal Gesetze, Wahlen und Gerichte — der Unterschied liegt im materiellen Gehalt. Im Rechtsstaat binden das Legalitätsprinzip den Staat an Gesetze, die Gewaltenteilung verhindert Machtkonzentration, und die Grundrechte schützen die Bürger vor staatlicher Willkür. In autoritären Staaten fehlen diese Garantien in der Realität.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Autoritäre Staaten haben formal auch Wahlen — aber oft ohne echte Wahlmöglichkeit.' }, { feld: 'optionen', id: 'opt-1', text: 'Gerichte gibt es in autoritären Staaten — nur sind sie oft nicht unabhängig.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Legalität + Gewaltenteilung + Grundrechteschutz sind rechtsstaatliche Kennzeichen.' }, { feld: 'optionen', id: 'opt-3', text: 'Gesetze gibt es auch in autoritären Staaten — der Unterschied liegt in der Anwendung.' } ] },
  { id: 'a7d9c777-4304-4acb-b2ea-4bff101ccf05', fachbereich: 'Recht', musterlosung: 'Der erste Schritt für eine Mietzinssenkung ist ein schriftliches Herabsetzungsbegehren an den Vermieter (Art. 270a OR). Der Vermieter hat 30 Tage Zeit zur Stellungnahme. Reagiert er nicht oder lehnt ab, kann der Mieter innert 30 Tagen die Schlichtungsbehörde anrufen. Eine eigenmächtige Kürzung ist nicht zulässig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die Schlichtungsbehörde ist zweiter Schritt — nach erfolglosem Begehren an Vermieter.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Schriftliches Herabsetzungsbegehren als erster Schritt (Art. 270a OR).' }, { feld: 'optionen', id: 'opt-2', text: 'Kündigung ist keine sinnvolle erste Reaktion bei gewünschter Mietzinssenkung.' }, { feld: 'optionen', id: 'opt-3', text: 'Eigenmächtige Kürzung wäre Pflichtverletzung — nicht zulässig.' } ] },
  { id: 'a7db705c-7fb0-4948-8e93-cda7c6259fa8', fachbereich: 'Recht', musterlosung: 'OR 330b verpflichtet den Arbeitgeber, die wesentlichen Vertragsbedingungen schriftlich mitzuteilen. Das Fehlen dieser Mitteilung macht den Vertrag nicht ungültig — der Vertrag existiert durch mündliche Einigung (Formfreiheit nach OR 320 Abs. 2). Der Arbeitgeber hat die Pflicht nachträglich zu erfüllen; Verletzung kann zu Schadenersatz führen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Ungültigkeit durch fehlende Schriftlichkeit — Formfreiheit bleibt.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Vertrag gültig + AG muss nachträglich schriftlich informieren.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine Nichtigkeit — OR 330b ist Informationspflicht, keine Formvorschrift.' }, { feld: 'optionen', id: 'opt-3', text: 'Beliebige Kündigung wäre kein gesetzliches Rechtsmittel für den AN.' } ] },
  { id: 'a8bad6b3-76ee-4519-b8fc-38f5f0b8c829', fachbereich: 'Recht', musterlosung: 'Die Rechtspersönlichkeit beginnt nach Art. 31 Abs. 1 ZGB mit der vollendeten Geburt. Nach Abs. 2 ist das ungeborene Kind jedoch unter dem Vorbehalt rechtsfähig, dass es lebend geboren wird. Da das Kind zwei Wochen nach dem Erbfall lebend zur Welt kommt, wirkt seine Rechtsfähigkeit auf den Zeitpunkt der Empfängnis zurück. Es kann erben.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Mindestaltersgrenze fürs Erben — auch Säuglinge können Erben sein.' }, { feld: 'optionen', id: 'opt-1', text: 'Die Rechtsfähigkeit wirkt auf die Empfängnis zurück — nicht erst ab Geburt.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Nasciturus erbt, wenn lebend geboren (Art. 31 Abs. 2 ZGB).' }, { feld: 'optionen', id: 'opt-3', text: 'Falsch — Art. 31 Abs. 2 schützt gerade den Nasciturus.' } ] },
  { id: 'a95e104a-6759-4794-9972-a81225b294ab', fachbereich: 'Recht', musterlosung: 'Es gibt keine gesetzliche Pflicht, störende Mitschüler zurechtzuweisen. Das Verhalten der Schülergruppe entspricht einer gesellschaftlichen Erwartung (Sitte) — man erwartet, dass Mitschüler Anstandsregeln einhalten und sich gegenseitig darauf hinweisen. Eine innere moralische Überzeugung könnte zusätzlich wirken, aber der soziale Druck kommt aus der Sitte.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Sitte — gesellschaftliche Erwartung ohne gesetzliche Grundlage.' }, { feld: 'optionen', id: 'opt-1', text: 'Die Lehrerweisung wäre Recht — aber der Fall setzt keine solche voraus.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine gesetzliche Pflicht zur Zurechtweisung — also kein Recht.' }, { feld: 'optionen', id: 'opt-3', text: 'Moralische innere Überzeugung wäre möglich — der Fall spricht aber von Gruppendynamik.' } ] },
  { id: 'a9e68d22-976a-4c8c-97ab-01446b3b56c3', fachbereich: 'Recht', musterlosung: 'Art. 894 ZGB verbietet die Verfallklausel (lex commissoria) absolut: Eine Abrede, wonach die Pfandsache bei Nichtbegleichung ins Eigentum des Gläubigers fällt, ist nichtig — unabhängig von der Gläubigerart. Der Gläubiger muss stattdessen die Pfandsache verwerten lassen (Pfandverwertung über Betreibung).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die Bank darf nicht direkt Eigentümer werden — sie muss verwerten.' }, { feld: 'optionen', id: 'opt-1', text: 'Gläubigerart irrelevant — Verbot gilt absolut (auch bei Banken).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Verbotene Verfallklausel — nichtig nach Art. 894 ZGB.' }, { feld: 'optionen', id: 'opt-3', text: 'Zustimmung hebt das Verbot nicht auf — es ist zwingendes Recht.' } ] },
  { id: 'aa166986-36b1-4d0b-8e64-52a1a4e3d7ea', fachbereich: 'Recht', musterlosung: 'Der Grundlagenirrtum nach OR 24 Abs. 1 Ziff. 4 liegt vor, wenn sich der Irrende über eine bestimmte Tatsache geirrt hat, die nach Treu und Glauben als notwendige Grundlage des Vertrags angenommen wurde. Typisches Beispiel: beide Parteien gehen von der Echtheit eines Gemäldes aus — stellt sich diese als falsch heraus, liegt Grundlagenirrtum vor.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Irrtum über eine als Vertragsgrundlage vorausgesetzte Tatsache.' }, { feld: 'optionen', id: 'opt-1', text: 'Rechtsirrtum ist nicht direkt in OR 24 Abs. 1 Ziff. 4 gemeint.' }, { feld: 'optionen', id: 'opt-2', text: 'Rechenfehler wäre Erklärungsirrtum (OR 24 Abs. 1 Ziff. 3), kein Grundlagenirrtum.' }, { feld: 'optionen', id: 'opt-3', text: 'Finanzieller Eigenirrtum ist kein Grundlagenirrtum — beide Parteien müssten ihn teilen.' } ] },
  { id: 'aa3896e3-e0c0-4207-bb49-8ef34e2096f1', fachbereich: 'Recht', musterlosung: 'Die Generalprävention wirkt auf die Gesellschaft als Ganzes. Durch die Strafandrohungen im Gesetz und deren öffentliche Durchsetzung sollen alle Gesellschaftsmitglieder von strafbaren Handlungen abgehalten und die Normgeltung bekräftigt werden. Die Spezialprävention hingegen wirkt nur auf den konkreten Täter (Abschreckung, Resozialisierung, Sicherung).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das ist die Spezialprävention — individuelle Wirkung auf den Täter.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Generalprävention wirkt auf die Gesellschaft insgesamt.' }, { feld: 'optionen', id: 'opt-2', text: 'Finanzielle Schädigung ist kein Zweck des Strafrechts — Gleichbehandlung zählt.' }, { feld: 'optionen', id: 'opt-3', text: 'Genugtuung des Opfers gehört eher zur zivilrechtlichen Ebene.' } ] },
  { id: 'abbb5a78-5190-476f-9866-92a564b0d69f', fachbereich: 'Recht', musterlosung: 'Der Lehrvertrag (OR 344–355) ist eine besondere Form des Arbeitsvertrags mit zwingender Schriftform — eine Ausnahme vom Grundsatz der Formfreiheit. Die Schriftlichkeit schützt den Lehrling und schafft Klarheit über Ausbildungsinhalt, -dauer und gegenseitige Pflichten. Ohne Schriftform ist der Lehrvertrag nicht gültig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Arbeitsamt-Genehmigung erforderlich — die Schriftform genügt.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Schriftform zwingend (OR 344a) — Ausnahme von Formfreiheit.' }, { feld: 'optionen', id: 'opt-2', text: 'Beide Parteien unterschreiben — auch der Lehrling (oder sein Vertreter).' }, { feld: 'optionen', id: 'opt-3', text: 'Falsch — Schriftlichkeit ist beim Lehrvertrag gesetzlich verlangt.' } ] },
  { id: 'abc50601-da1a-4519-8506-6e9a13427cc0', fachbereich: 'Recht', musterlosung: 'Nach OR 321c muss der Arbeitnehmer Überstundenarbeit leisten, wenn dies notwendig und zumutbar ist. Es ist dispositives Recht — der Vertrag kann andere Regeln vorsehen. Der Ausgleich erfolgt durch gleichwertige Freizeit oder durch einen Lohnzuschlag von 25% (wenn nichts anderes vereinbart wurde).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht immer — nur bei Notwendigkeit und Zumutbarkeit.' }, { feld: 'optionen', id: 'opt-1', text: 'Überstunden sind nicht vollständig freiwillig — OR 321c verpflichtet bei Bedarf.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Pflicht bei Notwendigkeit und Zumutbarkeit (OR 321c).' }, { feld: 'optionen', id: 'opt-3', text: 'Keine Schriftform erforderlich — die Pflicht folgt aus OR 321c.' } ] },
  { id: 'ac83eaa0-d1e7-4d66-b1b9-c9572eb61fe2', fachbereich: 'Recht', musterlosung: 'Das Prüfschema nach Art. 36 BV umfasst vier Elemente: gesetzliche Grundlage (Abs. 1), öffentliches Interesse oder Schutz von Grundrechten Dritter (Abs. 2), Verhältnismässigkeit (Abs. 3) und Unantastbarkeit des Kerngehalts (Abs. 4). Die Zustimmung der betroffenen Person ist nicht erforderlich — Grundrechte schützen gerade auch gegen den Willen der Mehrheit.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Gesetzliche Grundlage (Art. 36 Abs. 1 BV).' }, { feld: 'optionen', id: 'opt-1', text: 'Zustimmung ist kein Prüfkriterium — Grundrechte gelten objektiv.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Öffentliches Interesse oder Grundrechte Dritter (Art. 36 Abs. 2 BV).' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Verhältnismässigkeit (Art. 36 Abs. 3 BV).' } ] },
  { id: 'aca72668-8c25-44a6-9aed-98955b6e80ec', fachbereich: 'Recht', musterlosung: 'Der Arbeitnehmer hat nach OR 330a Anspruch auf ein Arbeitszeugnis. Es muss wahr, klar und vollständig sein — negative Inhalte sind zulässig, wenn wahr, aber wohlwollend formuliert. Der Arbeitgeber kann das Zeugnis nicht verweigern. Bei Streit kann das Zeugnis gerichtlich durchgesetzt oder korrigiert werden.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Anspruch auf Zeugnis nach OR 330a.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Wahr, klar, vollständig und wohlwollend.' }, { feld: 'optionen', id: 'opt-2', text: 'Falsch — wahrheitsgetreue negative Aussagen sind zulässig.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine Verweigerung möglich — der Anspruch ist zwingend.' } ] },
  { id: 'ad0024b9-84d2-463c-8ab2-68a5e6f82f39', fachbereich: 'Recht', musterlosung: 'Personalsicherheiten (Konventionalstrafe, Reuegeld, Bürgschaft) bedeuten: Eine zusätzliche Person übernimmt eine Verpflichtung. Realsicherheiten (Kaution, Retentionsrecht, Pfand, Eigentumsvorbehalt) bedeuten: Ein Gegenstand oder Geldbetrag dient als Sicherheit. Der Unterschied liegt in der Natur der Sicherung — Person vs. Sache.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Realsicherheiten sind nicht auf Unternehmen beschränkt — auch Private nutzen sie.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Person vs. Sache/Geldbetrag als Sicherungsmittel.' }, { feld: 'optionen', id: 'opt-2', text: 'Preisvergleich ist kein Kategorienmerkmal.' }, { feld: 'optionen', id: 'opt-3', text: 'Es gibt klaren Unterschied — verschiedene Rechtskategorien.' } ] },
  { id: 'ad5d5079-12d6-4328-b942-d495c0296bcb', fachbereich: 'Recht', musterlosung: 'Bei der einfachen Bürgschaft (OR 492) kann der Bürge erst belangt werden, wenn der Hauptschuldner zahlungsunfähig ist. Bei der Solidarbürgschaft (OR 496) kann der Gläubiger bereits nach Mahnung des Hauptschuldners direkt den Bürgen in Anspruch nehmen — ohne vorherige Betreibung. Die Solidarbürgschaft bietet dem Gläubiger stärkeren Schutz.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Beide benötigen Schriftform — kein Unterschied hier.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Solidarbürgschaft erlaubt direkten Zugriff nach Mahnung (OR 496).' }, { feld: 'optionen', id: 'opt-2', text: 'Es gibt deutliche Unterschiede bei der Inanspruchnahme.' }, { feld: 'optionen', id: 'opt-3', text: 'Auch die Solidarbürgschaft braucht einen Höchstbetrag (OR 493).' } ] },
  { id: 'adf306cd-69c9-4ec8-a827-e92f38022372', fachbereich: 'Recht', musterlosung: 'Spielleiter und Strafrichter haben unterschiedliche Aufgaben: Der Schiedsrichter sorgt für den Spielablauf, der Strafrichter schützt die öffentliche Ordnung. Wer Spielregeln massiv missachtet und gefährlich handelt (z.B. grobes Foul mit Verletzung), kann strafrechtlich zur Rechenschaft gezogen werden — unabhängig von sportlichen Sanktionen (BGE 109 IV 102).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die gelbe Karte schliesst strafrechtliche Prüfung nicht aus — andere Rechtsebene.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Sportliche und rechtliche Sanktionen sind unabhängig.' }, { feld: 'optionen', id: 'opt-2', text: 'Strafrechtliche Prüfung ist nicht ausgeschlossen — BGE 109 IV 102.' }, { feld: 'optionen', id: 'opt-3', text: 'Auch grob fahrlässige Fouls können strafrechtlich relevant sein.' } ] },
  { id: 'aec624f5-afe7-4f87-8cba-3ffb78a05fcb', fachbereich: 'Recht', musterlosung: 'Das kollektive Arbeitsrecht regelt das Verhältnis zwischen Gruppen — Gewerkschaften/Arbeitnehmerverbände und Arbeitgeber/-verbände. Es schafft kollektive Vereinbarungen wie GAV (Gesamtarbeitsverträge) und NAV (Normalarbeitsverträge). Das individuelle Arbeitsrecht dagegen regelt das konkrete Verhältnis zwischen einzelnem AN und AG.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'GAV gelten branchen- und personenabhängig — nicht universell bindend.' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht nur kantonal — auch Bund und Sozialpartner erlassen kollektives Arbeitsrecht.' }, { feld: 'optionen', id: 'opt-2', text: 'Das wäre individuelles Arbeitsrecht — nicht kollektives.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Koordination zwischen AN-Verbänden und AG-Verbänden.' } ] },
  { id: 'aef68407-b508-450f-affe-7264602ad6c9', fachbereich: 'Recht', musterlosung: 'Ein Strafverfahren wird durch eine Strafanzeige (jede Person), einen Strafantrag (bei Antragsdelikten innerhalb von 3 Monaten durch das Opfer) oder durch die Staatsanwaltschaft von Amtes wegen (bei Offizialdelikten) eingeleitet. Eine Zivilklage gehört dagegen zum Zivilprozess.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Zivilklage leitet einen Zivilprozess ein — kein Strafverfahren.' }, { feld: 'optionen', id: 'opt-1', text: 'Schlichtung ist Zivilprozess-Vorstufe — nicht Strafverfahren.' }, { feld: 'optionen', id: 'opt-2', text: 'Selbstanzeige ist Unterfall — nicht der Regelfall.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Strafanzeige, Strafantrag oder Amtseinleitung.' } ] },
  { id: 'af008a18-f902-4179-90a9-eed5be1c9119', fachbereich: 'Recht', musterlosung: 'Nach OR 322 ist die schriftliche Lohnabrechnung zwingende Pflicht des Arbeitgebers. Sie schützt den Arbeitnehmer, dokumentiert Sozialversicherungsbeiträge und Steuern. Ein Verstoss ist Pflichtverletzung und kann zu Bussen (ArG/AHV) und Schadenersatz führen. Ein Verzicht durch AN-Zustimmung ist nicht möglich — die Vorschrift ist zwingend.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'AN behält Lohnanspruch — die Form ändert nichts daran.' }, { feld: 'optionen', id: 'opt-1', text: 'Zustimmung hebt die zwingende Vorschrift nicht auf.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Verstoss gegen OR 322 — Schriftform zwingend.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine Teilzeit-Ausnahme — OR 322 gilt für alle Arbeitsverhältnisse.' } ] },
  { id: 'b0230a37-f007-482a-a6d5-5bbbd16c8e7a', fachbereich: 'Recht', musterlosung: 'Das Privatrecht regelt koordinative Rechtsbeziehungen zwischen gleichberechtigten Rechtssubjekten — natürliche und juristische Personen. Die Parteien begegnen sich auf Augenhöhe (z.B. Käufer und Verkäufer). Im Gegensatz dazu regelt das öffentliche Recht subordinative Beziehungen zwischen Staat und Bürger (Über-/Unterordnung).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Koordinative Beziehungen zwischen gleichberechtigten Parteien.' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht nur natürliche Personen — auch juristische Personen sind erfasst.' }, { feld: 'optionen', id: 'opt-2', text: 'Nicht nur juristische Personen — auch natürliche Personen sind erfasst.' }, { feld: 'optionen', id: 'opt-3', text: 'Subordinative Beziehungen sind öffentliches Recht — nicht Privatrecht.' } ] },
  { id: 'b0f98409-03d6-4bce-8ded-7f9c3bcb39da', fachbereich: 'Recht', musterlosung: 'Nach OR 19/20 führen drei Arten von Vertragsinhalten zur Nichtigkeit: unmöglicher Inhalt (Erfüllung objektiv ausgeschlossen), widerrechtlicher Inhalt (gegen zwingendes Recht verstossend) und unsittlicher Inhalt (gegen die guten Sitten). Ein wirtschaftlich nachteiliger Vertrag ist grundsätzlich gültig (Vertragsfreiheit) — bei schwerer Übervorteilung allenfalls anfechtbar nach OR 21.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Unmöglicher Inhalt → nichtig (OR 20 Abs. 1).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Widerrechtlicher Inhalt → nichtig (OR 20 Abs. 1).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Unsittlicher Inhalt → nichtig (OR 20 Abs. 1).' }, { feld: 'optionen', id: 'opt-3', text: 'Nachteilig sein allein führt nicht zur Nichtigkeit — Vertragsfreiheit.' } ] },
  { id: 'b10510e6-b1cf-4db9-8dd8-1934da27df6d', fachbereich: 'Recht', musterlosung: 'Der Darlehensvertrag (Art. 312 OR) ist eine privatrechtliche Rechtsbeziehung. Bei Nichtrückzahlung muss Lukas als Gläubiger einen Zivilprozess gegen Marco als Schuldner einleiten. Das blosse Nichtzurückzahlen einer Schuld ist keine Straftat — Schulden können jedoch klageweise eingefordert werden.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nichtzurückzahlung ist keine Straftat — privatrechtliche Angelegenheit.' }, { feld: 'optionen', id: 'opt-1', text: 'Schulden können sehr wohl eingeklagt werden — Zivilprozess.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Zivilprozess — privatrechtliche Streitigkeit.' }, { feld: 'optionen', id: 'opt-3', text: 'Kein Verwaltungsverfahren — der Staat ist nicht Partei.' } ] },
  { id: 'b18d8869-a073-44f7-9af8-cfe69b0a6850', fachbereich: 'Recht', musterlosung: 'Die rechtfertigende Notwehr (Art. 15 StGB) liegt vor, wenn die Abwehr eines rechtswidrigen Angriffs den Umständen angemessen ist → Straffreiheit. Die entschuldbare Notwehr (Art. 16 StGB) greift, wenn die Grenzen der Notwehr überschritten werden. Bei Überschreitung in entschuldbarer Aufregung entfällt die Schuld (Abs. 2), sonst wird die Strafe gemildert (Abs. 1).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Antragsdelikt-Unterscheidung — beide werden von Amtes wegen geprüft.' }, { feld: 'optionen', id: 'opt-1', text: 'Beide gelten gegen jeden rechtswidrigen Angriff — auch auf Sachen.' }, { feld: 'optionen', id: 'opt-2', text: 'Es gibt Unterschiede — entschuldbare Notwehr kann zu Strafmilderung oder Straffreiheit führen.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Rechtfertigend = angemessene Abwehr; entschuldbar = Grenzüberschreitung.' } ] },
  { id: 'b1f50e04-04da-4edf-8466-5c8bab1cd235', fachbereich: 'Recht', musterlosung: 'Ein Versammlungsverbot greift primär in die Versammlungsfreiheit (Art. 22 BV) ein. Da Versammlungen oft der Meinungsäusserung dienen, ist auch Art. 16 BV (Meinungsäusserungsfreiheit) betroffen. Zusätzlich wird die persönliche Freiheit (Art. 10 Abs. 2 BV, Bewegungsfreiheit) eingeschränkt. Ein gesundheitspolitischer Zweck kann öffentliches Interesse begründen — ändert aber nichts am Grundrechtseingriff.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht nur Art. 22 — auch Art. 16 und Art. 10 sind betroffen.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Mehrere Grundrechte betroffen — Art. 22, 16 und 10 BV.' }, { feld: 'optionen', id: 'opt-2', text: 'Nicht nur persönliche Freiheit — auch Versammlungs- und Meinungsäusserungsfreiheit.' }, { feld: 'optionen', id: 'opt-3', text: 'Falsch — Grundrechte werden sehr wohl eingeschränkt; der Zweck rechtfertigt allenfalls.' } ] },
  { id: 'b231ae38-de4c-4989-8e92-1d921c7a7be2', fachbereich: 'Recht', musterlosung: 'Bei Grundstücksstreitigkeiten gilt die besondere Zuständigkeitsregel: Das Gericht am Ort des Grundstücks ist zuständig (forum rei sitae) — hier also Interlaken. Der Streitwert von CHF 400\'000 liegt weit über CHF 30\'000, daher gilt das ordentliche Verfahren mit einem Kollegialgericht. Das Bundesgericht ist keine erstinstanzliche Instanz.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Beklagtenwohnsitz gilt bei Grundstücksstreitigkeiten gerade nicht — Grundstücksort.' }, { feld: 'optionen', id: 'opt-1', text: 'BG ist oberste Instanz — nicht erste Instanz.' }, { feld: 'optionen', id: 'opt-2', text: 'Nicht Bern (Klägerwohnsitz) und nicht vereinfachtes Verfahren — Streitwert zu hoch.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Gericht am Grundstücksort, ordentliches Verfahren.' } ] },
  { id: 'b261b788-084a-45c9-bc21-8fe632b7ea77', fachbereich: 'Recht', musterlosung: 'Grundrechte haben primär eine Abwehrfunktion: Sie verpflichten den Staat, in die geschützten Bereiche der Einzelnen nicht einzugreifen. Sie schützen die individuelle Freiheitssphäre gegen staatliche Übergriffe. Daneben haben Grundrechte auch Leistungs- und Schutzpflichten — das ist aber nicht die Kernfunktion.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Landesverteidigung ist keine Grundrechtsfunktion im engeren Sinn.' }, { feld: 'optionen', id: 'opt-1', text: 'Das wäre mittelbare Drittwirkung — und gilt in der Schweiz nur indirekt.' }, { feld: 'optionen', id: 'opt-2', text: 'Grundrechte wirken auch gegen Gerichte — aber Abwehr gegen Staat ist Kern.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Grundrechte schützen gegen ungerechtfertigte staatliche Eingriffe.' } ] },
  { id: 'b28fa3c9-5942-46b3-b0a7-187558a6023a', fachbereich: 'Recht', musterlosung: 'Relativ zwingendes Recht sind Bestimmungen, die nur zugunsten einer (meist schwächeren) Partei abgeändert werden dürfen — nicht zu deren Nachteil. Beispiel: Im Arbeitsrecht darf vertraglich ein höherer Mindestlohn, aber kein niedrigerer als der GAV- oder gesetzliche Mindestlohn vereinbart werden.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht auf Verwandte beschränkt — bezieht sich auf die Änderungsrichtung.' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht die Häufigkeit der Anwendung — Abweichungsrichtung zählt.' }, { feld: 'optionen', id: 'opt-2', text: 'Nicht teilweise zwingend — Abweichung nur in eine Richtung (zugunsten).' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Nur zugunsten der schwächeren Partei abänderbar.' } ] },
  { id: 'b2a44567-6c5e-4ae2-b476-76062512eca6', fachbereich: 'Recht', musterlosung: 'Die ordentliche Kündigung (OR 335 ff.) erfordert die Einhaltung der Kündigungsfristen: 7 Tage in der Probezeit, 1 Monat im 1. Dienstjahr, 2 Monate im 2.–9., 3 Monate ab 10. Dienstjahr. Die ausserordentliche (fristlose) Kündigung nach OR 337 ist sofort möglich, erfordert aber einen wichtigen Grund, der die Fortsetzung unzumutbar macht.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Es gibt einen klaren Unterschied — Fristen vs. sofortige Wirkung.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Ordentlich mit Frist, ausserordentlich sofort.' }, { feld: 'optionen', id: 'opt-2', text: 'Verdreht — ausserordentliche Kündigung braucht den wichtigen Grund.' }, { feld: 'optionen', id: 'opt-3', text: 'Schriftlichkeit wird beiden empfohlen — aber nicht für alle zwingend vorgesehen.' } ] },
  { id: 'b310532d-8ace-4d69-85c0-d94a7899e52e', fachbereich: 'Recht', musterlosung: 'Hunde benötigen grundsätzlich die Einwilligung des Vermieters. Ein laut bellender Hund, der die Nachbarschaft stört, kann einen Beseitigungsanspruch auslösen. Für eine ausserordentliche Kündigung nach Art. 257f Abs. 3 OR braucht es eine schriftliche Mahnung und eine angemessene Frist von 30 Tagen auf Monatsende. Eine sofortige fristlose Kündigung ist nicht zulässig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Haustiere sind nicht generell erlaubt — meist vermieterbedürftig.' }, { feld: 'optionen', id: 'opt-1', text: 'Die Störung liegt im Bellen, nicht in der Unterbringung.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Beseitigung verlangbar; Kündigung nur nach Mahnung + Frist (Art. 257f Abs. 3 OR).' }, { feld: 'optionen', id: 'opt-3', text: 'Keine sofortige Kündigung — Mahnung ist Voraussetzung.' } ] },
  { id: 'b33445fa-83fd-483f-9242-8d1c7593d0e5', fachbereich: 'Recht', musterlosung: 'Eine Grunddienstbarkeit besteht zugunsten des jeweiligen Eigentümers eines herrschenden Grundstücks — sie ist mit dem Grundstück verbunden und geht beim Verkauf auf den neuen Eigentümer über. Eine persönliche Dienstbarkeit besteht zugunsten einer bestimmten Person (z.B. Wohnrecht, Nutzniessung) und ist nicht übertragbar.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Es gibt einen klaren Unterschied — verschiedene Berechtigungsformen.' }, { feld: 'optionen', id: 'opt-1', text: 'Die Bezeichnungen betreffen nicht den Inhalt, sondern den Berechtigtentyp.' }, { feld: 'optionen', id: 'opt-2', text: 'Kosten sind kein Unterscheidungsmerkmal.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Grunddienstbarkeit zugunsten Grundstück, persönliche zugunsten Person.' } ] },
  { id: 'b341ac1c-3e41-49db-bcd2-a84fea062acb', fachbereich: 'Recht', musterlosung: 'Das StGB sieht neben Massnahmen (Art. 59–64 StGB) weitere Rechtsfolgen vor: Berufsverbot (Art. 67 StGB), Fahrverbot (Art. 67b StGB) und Einziehung von Gegenständen (Art. 69 StGB — z.B. Waffen, Drogen). Eine Steuererhöhung ist keine strafrechtliche Massnahme — Steuerrecht folgt eigenen Gesetzen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Berufsverbot ist im StGB vorgesehen (Art. 67).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Fahrverbot ist strafrechtliche Massnahme (Art. 67b StGB).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Gegenstandseinziehung nach Art. 69 StGB.' }, { feld: 'optionen', id: 'opt-3', text: 'Steuererhöhung ist Steuerrecht — kein strafrechtliches Instrument.' } ] },
  { id: 'b361129e-5eb7-42d1-bac2-60b2e1243177', fachbereich: 'Recht', musterlosung: 'Bei Gattungsschulden ist der Erfüllungsort nach OR 74 Abs. 2 Ziff. 3 am Wohnsitz des Schuldners — hier Luzern. Das Restaurant als Gläubiger müsste das Mehl dort abholen (Holschuld). Sendet der Bäcker es freiwillig via Post, geht das Transportrisiko grundsätzlich auf das Restaurant über, sobald der Bäcker die Ware dem Transporteur übergeben hat.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Restaurant trägt Risiko — Holschuld am Schuldnerwohnsitz.' }, { feld: 'optionen', id: 'opt-1', text: 'Die Post haftet nach eigenen Bestimmungen — aber die primäre Risikoverteilung läuft anders.' }, { feld: 'optionen', id: 'opt-2', text: 'Der Bäcker schuldet die Ware am eigenen Wohnsitz — keine Versandpflicht.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine hälftige Teilung — gesetzliche Regel ist eindeutig.' } ] },
  { id: 'b4807186-7d2e-4a2a-a8b3-5a3eb4ace820', fachbereich: 'Recht', musterlosung: 'Zwischen Wagner und dem Interessenten bestand ein Rechtsverhältnis (Vertragsverhandlung). Nach Art. 2 Abs. 1 ZGB gebieten es Treu und Glauben, dass Wagner den Absender sofort benachrichtigt, wenn der Briefumschlag leer ist. Berechtigtes Vertrauen darf nicht enttäuscht werden. Wagner hätte vor dem Verkauf an Dritte kontaktieren müssen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Der Vertrag kam nicht zustande — der Umschlag war leer, keine Annahme vorhanden.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Benachrichtigungspflicht nach Treu und Glauben (Art. 2 Abs. 1 ZGB).' }, { feld: 'optionen', id: 'opt-2', text: 'Der leere Umschlag befreit nicht von der Informationspflicht.' }, { feld: 'optionen', id: 'opt-3', text: 'Nicht «selbst schuld» — Wagner musste nach Treu und Glauben reagieren.' } ] },
  { id: 'b51d7725-4121-4555-9750-9370a124c530', fachbereich: 'Recht', musterlosung: 'Das Mietrecht ist in den Art. 253–274 OR geregelt. Die Artikel decken Grundlagen (Art. 253–256), Mietzins und Nebenkosten (Art. 257–258), Mängel (Art. 259–259i), Kündigung (Art. 266–266o), Mieterschutz (Art. 270–270e) und Erstreckung (Art. 272–274g) ab. Art. 184 ff. betreffen den Kaufvertrag, Art. 319 ff. den Arbeitsvertrag.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das ist das Kaufrecht — nicht Mietrecht.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Art. 253–274 OR regeln das Mietrecht.' }, { feld: 'optionen', id: 'opt-2', text: 'Das sind die allgemeinen Bestimmungen zum Vertragsabschluss.' }, { feld: 'optionen', id: 'opt-3', text: 'Das ist das Arbeitsrecht — anderer Vertragstyp.' } ] },
  { id: 'b5c1a8c5-5338-4d8b-b6fc-90eb16e123cc', fachbereich: 'Recht', musterlosung: 'Bei grundlegend und unvorhersehbar veränderten Umständen (clausula rebus sic stantibus) kann nach Treu und Glauben (Art. 2 Abs. 1 ZGB) eine Vertragsanpassung geboten sein. Im Lockdown-Fall argumentiert der Mieter, dass die Gegenleistung des Vermieters (Nutzbarkeit des Mietobjekts als Restaurant) faktisch nicht mehr möglich war — Mietzinsreduktion als Folge.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Rechtsmissbrauch (Abs. 2) setzt krass stossendes Verhalten voraus — hier geht es um Vertragsanpassung.' }, { feld: 'optionen', id: 'opt-1', text: 'Beweislast (Art. 8) regelt anderen Aspekt — nicht Vertragsanpassung.' }, { feld: 'optionen', id: 'opt-2', text: 'Guter Glaube (Art. 3) betrifft subjektives Wissen — nicht Vertragsanpassung.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Treu und Glauben (Art. 2 Abs. 1) — clausula rebus sic stantibus.' } ] },
  { id: 'b6001fa2-9be0-4509-84bf-7d938bf94d8f', fachbereich: 'Recht', musterlosung: 'Das Arbeitsrecht ist relativ zwingendes Recht: Abweichungen sind nur zugunsten des Arbeitnehmers zulässig (z.B. höherer Lohn, mehr Urlaub). Es dient dem Schutz der strukturell schwächeren Vertragspartei (AN). Volle Vertragsfreiheit wäre mit diesem Schutzzweck unvereinbar. Zwingende Mindeststandards können nicht unterschritten werden.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht absolut zwingend — Abweichungen zugunsten AN sind zulässig.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Relativ zwingend — zugunsten des AN abänderbar.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Schutz der schwächeren Partei (AN) ist zentraler Zweck.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine volle Vertragsfreiheit — Schutzcharakter schränkt sie ein.' } ] },
  { id: 'b62aaefc-e8d8-4173-9284-fe5de9c4186b', fachbereich: 'Recht', musterlosung: 'Die Mängelrüge nach OR 201 unterscheidet offene und versteckte Mängel: Offene Mängel sind sofort nach Erhalt zu rügen, versteckte nach Entdeckung. Ohne rechtzeitige Rüge gilt die Ware nach OR 200/201 als genehmigt — Mängelrechte entfallen. Die Form der Rüge ist nicht zwingend schriftlich, aber schriftlich ist beweissicherer.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Offene Mängel sofort rügen (OR 201).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Versteckte Mängel nach Entdeckung rügen.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Ohne Rüge Genehmigungsfiktion (OR 200/201).' }, { feld: 'optionen', id: 'opt-3', text: 'Formfreiheit — mündliche Rüge genügt, schriftlich ist aber beweissicherer.' } ] },
  { id: 'b676ab0d-4ff6-46d5-bd14-9af8d640189e', fachbereich: 'Recht', musterlosung: 'Yvonne hatte als Pfandgläubigerin kein Veräusserungsrecht — durfte das Bild aber aufbewahren. Beim Verkauf an die Galerie gilt Art. 933 ZGB: Da Daniel ihr das Bild anvertraut hatte, ist die gutgläubige Galerie geschützt und wurde Eigentümerin. Der Weiterverkauf an die gutgläubige Käuferin macht sie zur Eigentümerin. Daniel muss sich an Yvonne halten (Schadenersatz).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Art. 933 ZGB schützt gutgläubigen Erwerb — Daniel hat Eigentum verloren.' }, { feld: 'optionen', id: 'opt-1', text: 'Yvonne war nur Pfandgläubigerin, nicht Eigentümerin — Verkauf war unberechtigt.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Käuferin ist gutgläubige Eigentümerin — via Galerie (Art. 933 ZGB).' }, { feld: 'optionen', id: 'opt-3', text: 'Die Galerie hat das Bild weiterverkauft — nicht mehr in ihrem Eigentum.' } ] },
  { id: 'b731cae9-9395-487b-819c-f50ec80dbc26', fachbereich: 'Recht', musterlosung: 'Nach Art. 3 Abs. 2 ZGB kann sich nicht auf den guten Glauben berufen, wer bei der gebotenen Aufmerksamkeit nicht gutgläubig sein konnte. Der Hehler (bewusst), der Käufer im Drogenmilieu (Schleuderpreis, verdächtiger Ort) und der Occasionshändler ohne Papierprüfung (gesteigerte Sorgfaltspflicht) sind bösgläubig. Der reguläre Buchkauf ist unbedenklich.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Hehler kauft wissentlich Diebesgut — vorsätzlich bösgläubig.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Drogenmilieu + Schleuderpreis → Bösgläubigkeit aus den Umständen.' }, { feld: 'optionen', id: 'opt-2', text: 'Regulärer Buchkauf ist unverdächtig — guter Glaube gerechtfertigt.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Occasionshändler trifft erhöhte Sorgfaltspflicht (BGE 113 II 397).' } ] },
  { id: 'b806d763-3250-471c-9fd3-3994b515904b', fachbereich: 'Recht', musterlosung: 'Nach bundesgerichtlicher Rechtsprechung handelt es sich um Rechtsmissbrauch (Art. 2 Abs. 2 ZGB), wenn die rentenberechtigte Person in einem stabilen Konkubinat lebt, das eine eheähnliche Lebensgemeinschaft darstellt, und nur deshalb nicht heiratet, um den Rentenanspruch nicht zu verlieren. Das formelle Beharren auf dem Recht ist dann missbräuchlich.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht nur Treu-und-Glauben-Verstoss — das Verhalten erreicht die Rechtsmissbrauchs-Schwelle.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Rechtsmissbrauch — formelles Beharren ist missbräuchlich.' }, { feld: 'optionen', id: 'opt-2', text: 'Blosse gesetzliche Zulässigkeit des Zusammenlebens genügt nicht — Rentenzweck-Missbrauch.' }, { feld: 'optionen', id: 'opt-3', text: 'Der Rentenanspruch entfällt nicht automatisch — aber kann gerichtlich aberkannt werden.' } ] },
  { id: 'b90bb195-ff8c-497c-a423-13abce5d51e3', fachbereich: 'Recht', musterlosung: 'Art. 16 BV garantiert die Meinungs- und Informationsfreiheit: Jede Person hat das Recht, ihre Meinung frei zu bilden, zu äussern und zu verbreiten sowie Informationen frei zu empfangen und aus allgemein zugänglichen Quellen zu beschaffen. Art. 15 BV schützt die Glaubens- und Gewissensfreiheit, Art. 22 BV die Versammlungsfreiheit.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Eigentumsgarantie ist Art. 26 BV.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Meinungs- und Informationsfreiheit (Art. 16 BV).' }, { feld: 'optionen', id: 'opt-2', text: 'Versammlungsfreiheit ist Art. 22 BV.' }, { feld: 'optionen', id: 'opt-3', text: 'Religionsfreiheit ist Art. 15 BV.' } ] },
  { id: 'b95a02d8-2dcf-4394-8ee4-40f2f2a76ecb', fachbereich: 'Recht', musterlosung: 'Nach Art. 49 BV bricht Bundesrecht kantonales Recht (derogatorische Kraft). Ist der Bund in einem Rechtsgebiet zuständig — wie beim privaten Mietrecht (OR) — dürfen die Kantone keine widersprechenden Normen erlassen. Die kantonale Bestimmung ist wegen Art. 49 BV nichtig; es gilt die Bundesregelung (Art. 257a OR).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Vertragliche Vereinbarung kann zwingendes Recht nicht umgehen.' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht beide zugleich — Bundesrecht geht vor.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Bundesrecht bricht kantonales Recht (Art. 49 BV).' }, { feld: 'optionen', id: 'opt-3', text: 'Spezifität ist nicht entscheidend — Hierarchie der Rechtsquellen.' } ] },
  { id: 'ba055f12-e66b-4f61-af3c-46b85ae37746', fachbereich: 'Recht', musterlosung: 'Zwischen Vermieter und Untermieter besteht keine direkte Rechtsbeziehung (Art. 262 OR). Der Hauptmieter (Linus) ist allein dem Vermieter zum Mietzins verpflichtet. Die Untermieter (Lukas und Simon) schulden den Untermietzins nur Linus — der Vermieter kann sich nicht direkt an sie wenden. Risiko: Bei Beendigung des Hauptmietverhältnisses entfällt auch die Untermiete.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Kein direkter Zugriff — keine Rechtsbeziehung Vermieter-Untermieter.' }, { feld: 'optionen', id: 'opt-1', text: 'Untermieter müssen Untermietzins zahlen — an den Hauptmieter.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Nur Linus (Hauptmieter) schuldet dem Vermieter den Mietzins.' }, { feld: 'optionen', id: 'opt-3', text: 'Auch bei Insolvenz des Hauptmieters besteht keine direkte Beziehung.' } ] },
  { id: 'ba606d5c-b943-48ca-98fc-230507acd8d8', fachbereich: 'Recht', musterlosung: 'Die Mietzinshinterlegung (Art. 259g und 259h OR) ist das stärkste Druckmittel: Der Mieter kann den Mietzins bei einer von der Schlichtungsbehörde bezeichneten Stelle (amtliches Konto) hinterlegen, wenn der Vermieter trotz Aufforderung den Mangel nicht behebt. Die Hinterlegung muss schriftlich angedroht werden. Sie setzt den Vermieter unter Druck, ohne dass der Mieter in Schuldnerverzug gerät.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Renovation auf eigene Kosten ist keine gesetzliche Druckmöglichkeit.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Hinterlegung auf amtliches Konto (Art. 259g/h OR).' }, { feld: 'optionen', id: 'opt-2', text: 'Eigenmächtige Kürzung ist nicht zulässig — nur amtliche Hinterlegung.' }, { feld: 'optionen', id: 'opt-3', text: 'Mündliche Kündigung allein ist kein Druckmittel gegen Mängel.' } ] },
  { id: 'ba7f9993-178c-48a7-9157-ec0d28222db7', fachbereich: 'Recht', musterlosung: 'Nach Art. 47 Abs. 1 StGB bemisst das Gericht die Strafe nach dem Verschulden des Täters. Eine Strafe darf das Mass des individuellen Verschuldens nicht übersteigen — auch nicht aus generalpräventiven Gründen (Abschreckung anderer). Die Generalprävention wirkt bereits durch die Strafandrohung im Gesetz, nicht durch Übermassstrafen im Einzelfall.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Sicherheitsbedürfnisse rechtfertigen keine Übermassstrafe — Verschuldensprinzip gilt.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Strafe darf Verschulden nicht übersteigen (Art. 47 StGB).' }, { feld: 'optionen', id: 'opt-2', text: 'Auch geringer Diebstahl kann mit Freiheitsstrafe bestraft werden.' }, { feld: 'optionen', id: 'opt-3', text: 'Generalpräventive Straferhöhung über Verschulden hinaus ist unzulässig.' } ] },
  { id: 'bb740e1b-f46c-413a-b8ba-5264fce96479', fachbereich: 'Recht', musterlosung: 'Der Instanzenzug in der Schweiz verläuft in aufsteigender Reihenfolge: Bezirksgericht (erste Instanz) → Obergericht des Kantons (zweite Instanz, Berufungsinstanz) → Bundesgericht (höchste Instanz). Je nach Kanton und Streitwert steht ein Schlichtungsverfahren vor dem Bezirksgericht (z.B. Friedensrichter).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Bezirksgericht → Obergericht → Bundesgericht.' }, { feld: 'optionen', id: 'opt-1', text: 'Falsche Reihenfolge — Bezirksgericht ist erste Instanz.' }, { feld: 'optionen', id: 'opt-2', text: 'Bundesgericht ist oberste Instanz — nicht Zwischenstation.' }, { feld: 'optionen', id: 'opt-3', text: 'Umgekehrte Reihenfolge — der Zug geht von unten nach oben.' } ] },
  { id: 'bc161240-632a-4a9f-b73c-48d0c5ba3979', fachbereich: 'Recht', musterlosung: 'Anders als bei Freiheitsstrafen, die sich nach dem Verschulden richten (Art. 47 StGB), orientiert sich die Dauer einer Massnahme am Gesundheitszustand des Täters und am Sicherheitsbedürfnis der Allgemeinheit (Art. 59 Abs. 4 / Art. 60 Abs. 4 StGB). Die Massnahme endet, wenn der Behandlungszweck erreicht ist oder keine Gefahr mehr besteht.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Opferwünsche sind nicht ausschlaggebend.' }, { feld: 'optionen', id: 'opt-1', text: 'Falsch — Massnahmen folgen gerade nicht dem Verschuldensprinzip.' }, { feld: 'optionen', id: 'opt-2', text: 'Finanzielle Mittel dürfen die Dauer nicht bestimmen — Behandlungszweck zählt.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Gesundheitszustand + Sicherheitsbedürfnis bestimmen die Dauer.' } ] },
  { id: 'bc69fddf-2e9b-4bd6-b0e7-e219d7144260', fachbereich: 'Recht', musterlosung: 'Eine Stückschuld (Speziesschuld) liegt vor, wenn die geschuldete Sache individuell bestimmt ist (z.B. genau dieses Gemälde, dieser Oldtimer mit bestimmtem Kennzeichen). Bei einer Gattungsschuld ist die Sache nur nach Art und Menge bestimmt (z.B. 10 kg Mehl, 100 Eier). Die Unterscheidung hat Folgen für Erfüllungsort, Gefahrtragung und Unmöglichkeit.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das ist die Gattungsschuld — nur Art und Menge.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Individuell bestimmte Sache (z.B. dieses eine Gemälde).' }, { feld: 'optionen', id: 'opt-2', text: 'Das ist die Geldschuld — andere Kategorie.' }, { feld: 'optionen', id: 'opt-3', text: 'Das wäre Deliktsschuld — andere Entstehungsart.' } ] },
  { id: 'bcd401eb-8e31-4eaf-823a-39ade126fe5f', fachbereich: 'Recht', musterlosung: 'Bei einem Verfalltag kommt der Schuldner ohne Mahnung in Verzug (OR 102 Abs. 2). Die Gala-Lieferung ist ein Fixgeschäft (OR 108 Ziff. 3) — die Nachfrist ist entbehrlich. Im kaufmännischen Verkehr wird nach OR 190 vermutet, dass der Gläubiger auf die nachträgliche Leistung verzichtet und Schadenersatz wegen Nichterfüllung verlangt. Das Restaurant muss die verspätete Lieferung nicht annehmen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Verfalltag + Fixgeschäft + OR 190 — keine Annahmepflicht.' }, { feld: 'optionen', id: 'opt-1', text: 'Der Termin-Zweck (Gala) ist bereits im Verfalltag verankert.' }, { feld: 'optionen', id: 'opt-2', text: 'Bei Gala-Ausrichtung ist eine 2-tägige Verzögerung wesentlich.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine Nachfrist nötig — Fixgeschäft schliesst sie aus.' } ] },
  { id: 'bde9afad-8625-49a1-942a-32db1c07f75c', fachbereich: 'Recht', musterlosung: 'Der erste Schritt der Rechtsanwendung (Sachverhalt feststellen) klärt drei Kernfragen: Was ist passiert? Wer sind die Parteien? Welche Ansprüche machen sie geltend? Die Frage nach dem anwendbaren Gesetzesartikel gehört zum zweiten Schritt (Rechtsregel finden) — erst nach Klärung des Sachverhalts.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Was ist passiert? — Kernfrage der Sachverhaltsfeststellung.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Wer sind die Parteien? — Identifikation der Beteiligten.' }, { feld: 'optionen', id: 'opt-2', text: 'Gesetzesartikel-Frage gehört zu Schritt 2 (Rechtsregel finden).' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Welche Ansprüche? — Klärung der rechtlichen Positionen.' } ] },
  { id: 'be18907b-4cbd-4c86-96d4-c3280fe1cb96', fachbereich: 'Recht', musterlosung: 'Im Strafverfahren leitet die Staatsanwaltschaft die Untersuchung und erhebt ggf. Anklage. Der Beschuldigte hat das Recht auf einen Verteidiger (Verfahrensgarantie, Art. 32 BV). Es gilt die Unschuldsvermutung (Art. 10 StPO). Die Parteien heissen im Strafprozess Staatsanwaltschaft und Beschuldigter — «Kläger und Beklagter» sind Begriffe aus dem Zivilprozess.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Staatsanwaltschaft leitet Untersuchung und erhebt Anklage.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Verteidigerrecht als Verfahrensgarantie (Art. 32 BV).' }, { feld: 'optionen', id: 'opt-2', text: 'Falsch — Kläger/Beklagter sind Zivilprozessbegriffe.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Unschuldsvermutung gilt (Art. 10 StPO, Art. 32 BV).' } ] },
  { id: 'be7c3a27-a8d7-4595-b3cf-e8091a888d86', fachbereich: 'Recht', musterlosung: 'Nach der Lebensdauertabelle: Teppichboden = 10 Jahre, Kühlschrank = 15 Jahre. Nach 12 Jahren Mietdauer ist der Teppichboden vollständig abgeschrieben (Restlebensdauer 0) — der Mieter schuldet nichts. Der Kühlschrank hat noch 3 Jahre Restlebensdauer — der Mieter muss einen anteiligen Zeitwert bezahlen (3/15 der Kosten).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Nur Kühlschrank — Teppichboden abgeschrieben, Kühlschrank noch 3 Jahre Restwert.' }, { feld: 'optionen', id: 'opt-1', text: 'Teppichboden (10 Jahre Lebensdauer) ist nach 12 Jahren vollständig abgeschrieben.' }, { feld: 'optionen', id: 'opt-2', text: 'Umgekehrt — Teppichboden abgeschrieben, Kühlschrank noch Restwert.' }, { feld: 'optionen', id: 'opt-3', text: 'Kühlschrank (15 Jahre) ist nach 12 Jahren noch nicht vollständig abgeschrieben.' } ] },
  { id: 'becb2cf6-e792-42ca-b77e-2b1d02c8c787', fachbereich: 'Recht', musterlosung: 'Das Schweizer Strafrecht verfolgt drei Strafzwecke: (1) Vergeltung (vergangenheitsorientiert, Art. 47 Abs. 1 StGB), (2) Spezialprävention (Wirkung auf den Täter: Abschreckung, Resozialisierung, Sicherung) und (3) Generalprävention (Wirkung auf die Gesellschaft durch Strafandrohung und -durchsetzung). Alle drei Zwecke wirken zusammen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Entschädigung ist zivilrechtlich — nicht Strafzweck.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Vergeltung, Spezial- und Generalprävention.' }, { feld: 'optionen', id: 'opt-2', text: 'Opferschutz ist wichtig, aber kein eigenständiger Strafzweck.' }, { feld: 'optionen', id: 'opt-3', text: 'Rache ist nicht Ziel des Strafrechts — modernes Recht meidet den Begriff.' } ] },
  { id: 'bf16bf1b-13ed-46ab-88b4-7bf86b26fa0f', fachbereich: 'Recht', musterlosung: 'Das Obergericht ist im Kanton Bern die zweite Instanz. Die Berufung richtet sich gegen Urteile der ersten Instanz (Regionalgericht). Das Bundesgericht prüft grundsätzlich nur Rechtsfragen (korrekte Anwendung des Rechts), nicht den Sachverhalt. Nicht jeder Fall kann ans Bundesgericht weitergezogen werden — es gelten Streitwertgrenzen und formelle Voraussetzungen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Obergericht = zweite Instanz im Kanton Bern.' }, { feld: 'optionen', id: 'opt-1', text: 'Falsch — BG-Zugang hat Voraussetzungen (Streitwert, Rechtsfrage von grundlegender Bedeutung).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Berufung ist Rechtsmittel gegen erste Instanz.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: BG prüft grundsätzlich nur Rechtsfragen.' } ] },
  { id: 'bf5de48f-b544-4823-80d1-1f6c3c375f45', fachbereich: 'Recht', musterlosung: 'Das Tragen eines Kopftuchs ist Ausdruck der Religionsausübung und fällt unter die Glaubens- und Gewissensfreiheit (Art. 15 BV). Ein Verbot schränkt dieses Grundrecht ein. Die Zulässigkeit ist anhand von Art. 36 BV (gesetzliche Grundlage, öffentliches Interesse, Verhältnismässigkeit, Kerngehalt) zu prüfen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Glaubens- und Gewissensfreiheit (Art. 15 BV).' }, { feld: 'optionen', id: 'opt-1', text: 'Wirtschaftsfreiheit (Art. 27) betrifft Erwerbstätigkeit — nicht das Kopftuch-Tragen selbst.' }, { feld: 'optionen', id: 'opt-2', text: 'Versammlungsfreiheit (Art. 22) betrifft Gruppenzusammenkünfte.' }, { feld: 'optionen', id: 'opt-3', text: 'Meinungsäusserungsfreiheit (Art. 16) betrifft Ausdruck von Meinungen — nicht religiöse Kleidung.' } ] },
  { id: 'c197be58-f52c-40cd-a5a7-3eb642982cf3', fachbereich: 'Recht', musterlosung: 'Nach Art. 257e OR darf der Vermieter ein Mietzinsdepot (Kaution) von maximal drei Monatsmieten (Bruttomieten) verlangen. Das Depot wird auf einem Sperrkonto im Namen des Mieters bei einer Bank hinterlegt. Nach dem Auszug ist es spätestens ein Jahr nach Beendigung zurückzuerstatten — sofern keine berechtigten Forderungen bestehen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Max. 3 Monatsmieten nach Art. 257e OR.' }, { feld: 'optionen', id: 'opt-1', text: '1 Monatsmiete ist zu wenig — Gesetz erlaubt bis zu 3.' }, { feld: 'optionen', id: 'opt-2', text: '2 Monatsmieten sind unter dem Maximum — aber nicht die Obergrenze.' }, { feld: 'optionen', id: 'opt-3', text: '6 Monatsmieten wären nicht zulässig — Art. 257e begrenzt auf 3.' } ] },
  { id: 'c1b11d19-b12a-4f2c-ab04-0b3f42bc29cc', fachbereich: 'Recht', musterlosung: 'Die Grundlast nach Art. 782 ZGB verpflichtet den jeweiligen Eigentümer eines Grundstücks zu einer Leistung an den Berechtigten, wofür er ausschliesslich mit dem Grundstück haftet. Beispiele: Obstlieferungen, Wasserversorgung, Unterhaltspflicht für eine Mauer. Der Schuldner wechselt mit jedem Eigentümerwechsel — das Grundstück selbst ist das Haftungsobjekt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Leistungsverpflichtung mit Haftung nur über das Grundstück (Art. 782 ZGB).' }, { feld: 'optionen', id: 'opt-1', text: 'Grundsteuer ist öffentliches Abgaberecht — keine Grundlast im ZGB-Sinn.' }, { feld: 'optionen', id: 'opt-2', text: 'Umweltbelastung ist faktisch, nicht rechtlich Grundlast.' }, { feld: 'optionen', id: 'opt-3', text: 'Dienstbarkeit ist andere Rechtsform — Duldung statt Leistung.' } ] },
  { id: 'c2390133-f726-4c0c-9068-491c88a04fb1', fachbereich: 'Recht', musterlosung: 'Das Schweizer Recht kennt mehrere Formstufen: Formfreiheit (Grundsatz, OR 11), einfache Schriftlichkeit (z.B. Bürgschaft OR 493), qualifizierte Schriftlichkeit (z.B. eigenhändige Unterschrift und weitere Angaben) und öffentliche Beurkundung (z.B. Grundstückkauf, ZGB 216, durch Notar). Die Formstufen schützen unterschiedlich stark.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Unvollständig — qualifizierte Formen fehlen.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Einfache Schriftlichkeit, qualifizierte Schriftlichkeit, öffentliche Beurkundung.' }, { feld: 'optionen', id: 'opt-2', text: 'Öffentliche Beurkundung ist nur eine Stufe — nicht allein.' }, { feld: 'optionen', id: 'opt-3', text: 'Digitale Signatur ist technische Variante, nicht eigene Formstufe.' } ] },
  { id: 'c32d241e-3b78-4dfa-aa8f-2bedb0ba236b', fachbereich: 'Recht', musterlosung: 'Die Untermiete ist in Art. 262 OR geregelt. Der Mieter darf die Mietsache mit Zustimmung des Vermieters ganz oder teilweise untervermieten. Die Zustimmung kann nur aus drei Gründen verweigert werden: fehlende Offenlegung der Bedingungen, missbräuchliche Bedingungen, wesentliche Nachteile für den Vermieter.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Art. 254 regelt andere mietrechtliche Grundlagen.' }, { feld: 'optionen', id: 'opt-1', text: 'Art. 272 regelt die Erstreckung — nicht Untermiete.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Art. 262 OR regelt die Untermiete.' }, { feld: 'optionen', id: 'opt-3', text: 'Art. 259 regelt Mängelrechte — nicht Untermiete.' } ] },
  { id: 'c339a10a-4b5b-4584-8641-2a16579283b8', fachbereich: 'Recht', musterlosung: 'Art. 13 ZGB hat zwei Tatbestandsmerkmale: TBM 1 (volljährig, Art. 14 ZGB) und TBM 2 (urteilsfähig, Art. 16 ZGB). Beide müssen kumulativ erfüllt sein. Rechtsfolge: Die Person ist handlungsfähig (kann selbstständig Rechtsgeschäfte abschliessen). «Handlungsfähig» ist die Rechtsfolge, nicht das TBM.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Handlungsfähig ist die RF, nicht das TBM.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: TBM 1 volljährig + TBM 2 urteilsfähig (Art. 13 ZGB).' }, { feld: 'optionen', id: 'opt-2', text: 'Schweizer Bürgerschaft ist nicht Voraussetzung der Handlungsfähigkeit.' }, { feld: 'optionen', id: 'opt-3', text: 'Die gesetzlichen Begriffe sind volljährig und urteilsfähig — nicht 18/gesund.' } ] },
  { id: 'c3a19eb2-19b5-4a0e-83d0-de74bfea6d09', fachbereich: 'Recht', musterlosung: 'Urteilsfähige Unmündige werden nach Art. 19 Abs. 3 ZGB für Schaden aus unerlaubten Handlungen ersatzpflichtig (Deliktsfähigkeit). Die beschränkte Handlungsunfähigkeit schützt nur vor rechtsgeschäftlichen Verpflichtungen (z.B. Kaufvertrag ohne Zustimmung), nicht vor Haftung aus Delikt. Hansli ist 16 und urteilsfähig — er muss den Schaden am Mercedes ersetzen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Eltern haften nur bei Verletzung der Aufsichtspflicht (Art. 333 ZGB).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Urteilsfähige Unmündige haften für Delikte (Art. 19 Abs. 3 ZGB).' }, { feld: 'optionen', id: 'opt-2', text: 'Minderjährige haften sehr wohl — bei Urteilsfähigkeit (Deliktsfähigkeit).' }, { feld: 'optionen', id: 'opt-3', text: 'Die Haftung ist unabhängig von einer Anzeige — zivilrechtlicher Anspruch.' } ] },
  { id: 'c4347ad2-1f3f-4cd8-abe8-e14919d9c5ab', fachbereich: 'Recht', musterlosung: 'Das ArG gilt für Betriebe aller Grössen — auch kleine unterliegen den Schutzbestimmungen. Nachtarbeit (23:00–06:00) erfordert nach ArG 16–20 einen Lohnzuschlag von mindestens 25%. Eine Zustimmung der Arbeitnehmer hebt diese zwingende Vorschrift nicht auf — das ArG ist zum Schutz der AN konzipiert.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Falsch — das ArG gilt für alle Betriebsgrössen.' }, { feld: 'optionen', id: 'opt-1', text: 'Nachtarbeit ist grundsätzlich erlaubt — mit Zuschlag und Bewilligung.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Nachtarbeit-Zuschlag nach ArG 16–20 ist zwingend.' }, { feld: 'optionen', id: 'opt-3', text: 'AN-Zustimmung kann zwingendes ArG nicht umgehen.' } ] },
  { id: 'c575b285-4f34-478e-bc7f-b83ccde0a388', fachbereich: 'Recht', musterlosung: 'Nach Art. 54 OR ist ersatzpflichtig, wer in einem vorübergehenden Zustand der Urteilsunfähigkeit Schaden verursacht — ausser er weist nach, dass der Zustand ohne sein Verschulden eingetreten ist. Hans hat sich freiwillig betrunken; der Rauschzustand wurde von ihm selbst verschuldet. Er muss den Schaden ersetzen (Art. 54 Abs. 1 OR).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Der Schaden muss zwar bewiesen werden — aber die Haftung folgt aus Art. 54 OR.' }, { feld: 'optionen', id: 'opt-1', text: 'Kein «Unfall» im Rechtssinne — Hans trifft Mitverschulden durch Rauschzustand.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Haftung nach Art. 54 OR bei selbst verschuldetem Rausch.' }, { feld: 'optionen', id: 'opt-3', text: 'Urteilsunfähige haften bei selbst verschuldetem Zustand (Art. 54 OR).' } ] },
  { id: 'c5cc38fa-425a-4f95-8945-f6109d7f67ea', fachbereich: 'Recht', musterlosung: 'Art. 8 ZGB enthält die grundlegende Beweislastregel: Wer aus einer behaupteten Tatsache Rechte ableitet, muss die Tatsache beweisen. Dies ist zentral, weil bei unklarem Sachverhalt entschieden werden muss, wer die Beweislosigkeit trägt. Die Norm verhindert, dass unklare Sachverhalte den Rechtsstreit blockieren.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Unschuldsvermutung gilt nur im Strafprozess — nicht Art. 8 ZGB.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Beweislastverteilung als Grundnorm für den Zivilprozess.' }, { feld: 'optionen', id: 'opt-2', text: 'Kein Schriftformerfordernis — verschiedene Beweismittel zulässig.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine Amtsermittlung im Zivilprozess — Parteien bringen die Beweise.' } ] },
  { id: 'c5dacb23-bac5-456f-a02f-a6ce2c3f30d2', fachbereich: 'Recht', musterlosung: 'Im Strafprozessrecht gilt die Untersuchungsmaxime: Der Sachverhalt wird von Amtes wegen abgeklärt. Die Strafverfolgungsbehörden (Polizei, Staatsanwaltschaft) haben die Aufgabe, die Wahrheit zu ermitteln — belastende und entlastende Umstände gleichermassen. Der Beschuldigte muss seine Unschuld nicht beweisen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Kein Gutdünken — der Richter folgt den Beweisen.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Untersuchungsmaxime im Strafprozess — Wahrheitsermittlung von Amtes wegen.' }, { feld: 'optionen', id: 'opt-2', text: 'Behauptungslast ist ein Zivilprozessbegriff — im Strafrecht dominiert Amtsermittlung.' }, { feld: 'optionen', id: 'opt-3', text: 'Verhandlungsmaxime gilt im Zivilprozess — nicht im Strafverfahren.' } ] },
  { id: 'c69a9371-ad24-40ea-8ead-064f8c81333d', fachbereich: 'Recht', musterlosung: 'Nach Art. 271a Abs. 1 lit. a OR ist eine Kündigung anfechtbar, wenn sie ausgesprochen wird, weil der Mieter Ansprüche aus dem Mietverhältnis geltend macht (z.B. Mietzinsanfechtung). Frau Müller hat ein gesetzlich vorgesehenes Recht wahrgenommen — die Kündigung als Reaktion darauf ist mit hoher Wahrscheinlichkeit eine missbräuchliche Rachekündigung und kann bei der Schlichtungsbehörde angefochten werden.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht jederzeit kündbar — Rachekündigungen sind anfechtbar.' }, { feld: 'optionen', id: 'opt-1', text: 'Die Form ist nicht das Problem — die Motivation der Kündigung zählt.' }, { feld: 'optionen', id: 'opt-2', text: 'Rechtswahrnehmung darf nicht sanktioniert werden — Kündigung ist anfechtbar.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Rachekündigung anfechtbar nach Art. 271a Abs. 1 lit. a OR.' } ] },
  { id: 'c6c3aa58-87df-4204-badf-5117c2179944', fachbereich: 'Recht', musterlosung: 'Die Berufung ist das ordentliche Rechtsmittel gegen Urteile der ersten Instanz im Zivilprozess. Die unterlegene Partei kann damit das Urteil beim Obergericht (zweite Instanz) anfechten. Das Obergericht überprüft den Fall in tatsächlicher und rechtlicher Hinsicht — nicht nur wie das Bundesgericht auf Rechtsfragen beschränkt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das wäre die Beschwerde in Zivilsachen ans Bundesgericht.' }, { feld: 'optionen', id: 'opt-1', text: 'Das wäre die Klageantwort — nicht ein Rechtsmittel.' }, { feld: 'optionen', id: 'opt-2', text: 'Das ist die Einleitung in die Schlichtung — nicht ein Rechtsmittel.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Rechtsmittel gegen erstinstanzliches Urteil, geht ans Obergericht.' } ] },
  { id: 'c6e03705-3f47-4244-a90c-9fd88111f45b', fachbereich: 'Recht', musterlosung: 'Die Geldstrafe (Art. 34 StGB) wird in Tagessätzen (1–180) bemessen, die Höhe (CHF 30 bis CHF 3\'000) richtet sich nach persönlichen und wirtschaftlichen Verhältnissen. Sie betrifft Vergehen. Die Busse (Art. 103, Art. 106 StGB) ist ein fixer Betrag bis CHF 10\'000 und betrifft Übertretungen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Geldstrafe = Tagessätze (Vergehen), Busse = fixer Betrag (Übertretungen).' }, { feld: 'optionen', id: 'opt-1', text: 'Es gibt einen deutlichen Unterschied — verschiedene Strafarten für verschiedene Delikte.' }, { feld: 'optionen', id: 'opt-2', text: 'Verbrechen werden mit Freiheitsstrafe geahndet — nicht (nur) mit Geldstrafe.' }, { feld: 'optionen', id: 'opt-3', text: 'Verdreht — Geldstrafe wird in Tagessätzen bemessen, nicht Busse.' } ] },
  { id: 'c6e3410e-5f91-4f4f-9f4f-24e6a106dc58', fachbereich: 'Recht', musterlosung: 'Das Gewaltmonopol ist zentral für den Rechtsfrieden, weil es Selbstjustiz ausschliesst. Konflikte werden nach einheitlichen Regeln durch unabhängige Gerichte gelöst (Rechtskraft). Ohne Gewaltmonopol drohten Eskalation, Fehden und Rechtsunsicherheit. Das Monopol ist die Voraussetzung dafür, dass der Staat Grundrechte und Rechtsgleichheit sicherstellen kann.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Gewaltmonopol ist nicht Willkür — es wird durch Legalitätsprinzip und Grundrechte begrenzt.' }, { feld: 'optionen', id: 'opt-1', text: 'Bürger können sich sehr wohl gegen staatliches Unrecht wehren (Rechtsmittel, Grundrechtsklage).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Keine Selbstjustiz + einheitliche Gerichtsbarkeit.' }, { feld: 'optionen', id: 'opt-3', text: 'Gesetze gibt es auch ohne Gewaltmonopol — das Problem ist deren Durchsetzung.' } ] },
  { id: 'c70f0508-face-42e0-8c61-c11002dcfd85', fachbereich: 'Recht', musterlosung: 'Der Kaufvertrag begründet nur ein obligatorisches (relatives) Recht — K hat einen Anspruch gegen V auf Übergabe. Für den Eigentumserwerb an beweglichen Sachen ist nach Art. 714 ZGB jedoch die Besitzübertragung erforderlich. K hat den Wagen nie erhalten; V hat ihn an C übergeben. C ist durch Besitzübergabe Eigentümer geworden. K kann den Wagen nicht von C herausverlangen — nur Schadenersatz von V fordern.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Der Kaufvertrag allein überträgt kein Eigentum — Besitzübergabe notwendig.' }, { feld: 'optionen', id: 'opt-1', text: 'Gebrauchtwagenkauf ist normal bindend — kein Sonderfall.' }, { feld: 'optionen', id: 'opt-2', text: 'Zahlung allein begründet kein Eigentum — Besitz ist entscheidend.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: K hat nur obligatorischen Anspruch gegen V — kein dingliches Recht.' } ] },
  { id: 'ca1aa247-0f7b-42b7-b390-cbb23906a853', fachbereich: 'Recht', musterlosung: 'Art. 641 ZGB gibt dem Eigentümer die alleinige Herrschaft über die Sache: er darf sie nutzen, verkaufen, vermieten, verschenken, verpfänden, ändern oder zerstören (positive Herrschaft), sie von jedem herausverlangen (Vindikation) und Einwirkungen abwehren (Abwehrklage). Allerdings nur innerhalb der Schranken der Rechtsordnung — Bau- und Zonenordnung schränken die Verfügungsfreiheit ein.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Positive Herrschaftsbefugnisse (nutzen, veräussern, zerstören).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Herausgabeanspruch (Vindikation) nach Art. 641 Abs. 2 ZGB.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Abwehrklage gegen ungerechtfertigte Einwirkungen.' }, { feld: 'optionen', id: 'opt-3', text: 'Falsch — öffentlich-rechtliche Vorschriften sind zu beachten (Art. 641 Abs. 1 ZGB).' } ] },
  { id: 'ca24f4b3-4952-4884-80eb-da94a09fb005', fachbereich: 'Recht', musterlosung: 'Art. 1 ZGB ist der zentrale Einleitungsartikel, der die Rechtsquellen aufzählt, auf die sich das Gericht stützt: (1) geschriebenes Recht (Gesetze), (2) Gewohnheitsrecht bei Gesetzeslücken, (3) richterliche Rechtsfindung nach der Regel, die der Richter als Gesetzgeber aufstellen würde (Art. 1 Abs. 2 ZGB).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Art. 3 ZGB regelt den guten Glauben.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Art. 1 ZGB regelt die Rechtsquellen.' }, { feld: 'optionen', id: 'opt-2', text: 'Art. 8 ZGB regelt die Beweislast.' }, { feld: 'optionen', id: 'opt-3', text: 'Art. 2 ZGB regelt Treu und Glauben sowie Rechtsmissbrauch.' } ] },
  { id: 'cab5aba2-8f95-46d8-9be7-8f869b7ca027', fachbereich: 'Recht', musterlosung: 'Das Arbeitsrecht folgt dem Prinzip der relativen Zwingendheit: Abweichungen von gesetzlichen Minimalstandards sind nur zugunsten des Arbeitnehmers zulässig. Eine Reduktion des Urlaubsanspruchs unter das gesetzliche Mindestmass ist daher nichtig — der gesetzliche Standard bleibt bestehen. Umgekehrt ist ein höherer Urlaubsanspruch zulässig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Absolute Zwingendheit würde keine Abweichungen erlauben — Arbeitsrecht ist relativ zwingend.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine Genehmigung — Nichtigkeit tritt ex lege ein.' }, { feld: 'optionen', id: 'opt-2', text: 'Vertragsfreiheit wird durch zwingendes Arbeitsrecht eingeschränkt.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Relative Zwingendheit — Abweichung nur zugunsten des AN.' } ] },
  { id: 'cae8aff3-07cd-4d9e-aa73-08faf6b9104c', fachbereich: 'Recht', musterlosung: 'Der Mieter haftet nur für übermässige Beschädigungen — nicht für normale Abnutzung. (1) Kratzer durch einen schweren Schrank ohne Filzgleiter = unsachgemässer Gebrauch → Mieter haftet (zum Zeitwert). (2) Vergilbte Wände durch Kochen = normale Abnutzung → Vermieter trägt die Kosten. (3) Loch in der Wand = übermässige Beschädigung → Mieter haftet.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Kratzer durch unsachgemässen Gebrauch — Mieter haftet (Zeitwert).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Vergilbte Wände durch Kochen = normale Abnutzung, kein Mieter-Ersatz.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Loch in der Wand = übermässige Beschädigung, Mieter haftet.' }, { feld: 'optionen', id: 'opt-3', text: 'Falsch — Kratzer und Loch gehen über normale Abnutzung hinaus.' } ] },
  { id: 'cb9c2e4d-d972-49d2-9e2a-4794a5854631', fachbereich: 'Recht', musterlosung: 'Das Tagessatzsystem (Art. 34 StGB) gewährleistet Gleichheit: Die Anzahl Tagessätze (1–180) richtet sich nach dem Verschulden, die Höhe (CHF 30 bis CHF 3\'000) nach den persönlichen und wirtschaftlichen Verhältnissen. So trifft die gleiche Strafe (z.B. 30 Tagessätze) eine wohlhabende Person genauso hart wie eine Person mit geringem Einkommen — proportional zur Leistungsfähigkeit.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Gleichheitsprinzip — gleiche Belastung unabhängig vom Einkommen.' }, { feld: 'optionen', id: 'opt-1', text: 'Spielraum-Argument ist nicht der Hauptzweck — Gleichbehandlung zählt.' }, { feld: 'optionen', id: 'opt-2', text: 'Tagessatzsystem ist nicht EU-übernommen — Eigenentwicklung des Schweizer Strafrechts.' }, { feld: 'optionen', id: 'opt-3', text: 'Komplexer — Tagessätze sind aufwendiger zu berechnen als ein fixer Betrag.' } ] },
  { id: 'ccd2ec63-1732-428a-b9c3-625a92ee452a', fachbereich: 'Recht', musterlosung: 'Das OR kennt vier Willensmängel: Übervorteilung (OR 21), wesentliche Irrtümer (OR 23 ff., darunter Erklärungsirrtum OR 24 Abs. 1 Ziff. 1–3 und Grundlagenirrtum OR 24 Abs. 1 Ziff. 4), absichtliche Täuschung (OR 28) und Furchterregung (OR 29). Bei Willensmängeln ist der Vertrag anfechtbar — er bleibt gültig bis zur einseitigen Unverbindlichkeitserklärung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Unvollständig — drei weitere Willensmängel bestehen.' }, { feld: 'optionen', id: 'opt-1', text: 'Form-/Inhaltsfehler führen zur Nichtigkeit — nicht Willensmängel.' }, { feld: 'optionen', id: 'opt-2', text: 'Unvollständig — auch Übervorteilung und Furchterregung sind Willensmängel.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Übervorteilung, Irrtümer, absichtliche Täuschung, Furchterregung.' } ] },
]

// Duplikate filtern (defensiv)
const seen = new Set()
const filtered = updates.filter((u) => {
  if (seen.has(u.id)) return false
  seen.add(u.id)
  return true
})

const lines = filtered.map((u) => JSON.stringify(u)).join('\n') + '\n'
await fs.appendFile(OUT, lines)

const state = JSON.parse(await fs.readFile(STATE, 'utf8'))
state.letzteSession = new Date().toISOString()
state.verarbeitet = (state.verarbeitet || 0) + filtered.length
state.fragen = state.fragen || {}
for (const u of filtered) {
  state.fragen[u.id] = { status: 'done', zeitpunkt: state.letzteSession, teile: u.teilerklaerungen.length }
}
await fs.writeFile(STATE, JSON.stringify(state, null, 2))
console.log(`[s6] ${filtered.length} Updates | total ${state.verarbeitet}/${state.totalFragen}`)
